const intent = $json.intent || '';
const params = $json.intentParams || {};
const accessToken = $json.accessToken || '';
if (!accessToken) { return [{ json: { ...$json, responseText: '⚠️ Google Auth failed: no access token.', success: false } }]; }
let endpoint, queryParams, method = 'GET', body = null;
if (intent === 'contacts_list') {
  endpoint = 'https://people.googleapis.com/v1/people/me/connections';
  queryParams = { pageSize: Math.min(params.page_size || 10, 100), personFields: 'names,emailAddresses,phoneNumbers' };
} else if (intent === 'contacts_search') {
  endpoint = 'https://people.googleapis.com/v1/people:searchContacts';
  queryParams = { query: params.query || '', pageSize: 10, readMask: 'names,emailAddresses,phoneNumbers' };
} else if (intent === 'contacts_create') {
  const { names, emailAddresses, phoneNumbers } = params;
  if (!names || !names[0]?.displayName) return [{ json: { ...$json, responseText: '❗ At least one name with displayName required.', success: false } }];
  endpoint = 'https://people.googleapis.com/v1/people:createContact';
  method = 'POST';
  body = {};
  if (names) body.names = names;
  if (emailAddresses) body.emailAddresses = emailAddresses;
  if (phoneNumbers) body.phoneNumbers = phoneNumbers;
} else { return [{ json: { ...$json, responseText: '❓ Unknown Contacts intent: ' + intent, success: false } }]; }
return [{ json: { ...$json, apiEndpoint: endpoint, apiParams: queryParams, apiMethod: method, apiBody: body, bearerToken: accessToken, _ctx: { intent, params, accessToken, source: $json.source, userId: $json.userId, sessionId: $json.sessionId, inputText: $json.inputText } } }];

const ctx = $json._ctx || $('Build Request').first().json._ctx || {};
const connections = $json.connections || [];
if ($json.resourceName) { return [{ json: { ...ctx, responseText: '✅ Contact created successfully.', success: true, intent: ctx.intent } }]; }
if (connections.length === 0) { return [{ json: { ...ctx, responseText: '👤 No contacts found.', success: true, intent: ctx.intent } }]; }
let text = '👥 Contacts:

';
connections.forEach((c, i) => {
  const name = c.names?.[0]?.displayName || 'Unnamed';
  const email = c.emailAddresses?.[0]?.value || '';
  const phone = c.phoneNumbers?.[0]?.value || '';
  text += `${i+1}. <b>${name}</b>${email ? ' \n📧 ' + email : ''}${phone ? ' \n📱 ' + phone : ''}\n\n`;
});
return [{ json: { ...ctx, responseText: text, success: true, intent: ctx.intent } }];

const ctx = $json._ctx || $('Build Request').first().json._ctx || {};
const jarvisLog = (level, message, meta = {}) => {
  const levels = { debug: 0, info: 1, warn: 2, error: 3 };
  const configLevel = ($env.LOG_LEVEL || 'info').toLowerCase();
  if (levels[level] >= (levels[configLevel] ?? 1)) { console[level === 'error' ? 'error' : level === 'warn' ? 'warn' : 'log'](JSON.stringify({ timestamp: new Date().toISOString(), level, traceId: ctx.sessionId || 'unknown', workflow: 'contacts-agent', message, meta })); }
};
const statusCode = $json.statusCode || $json.error?.statusCode || 0;
const statusMessage = $json.statusMessage || $json.error?.message || 'Unknown error';
if (statusCode === 401) {
  jarvisLog('warn', 'Token expired, attempting refresh', { intent: ctx.intent });
  try {
    const authRes = await $helpers.httpRequest({ method: 'POST', url: 'https://oauth2.googleapis.com/token', headers: { 'Content-Type': 'application/x-www-form-urlencoded' }, body: 'client_id=' + encodeURIComponent($env.GOOGLE_CLIENT_ID) + '&client_secret=' + encodeURIComponent($env.GOOGLE_CLIENT_SECRET) + '&refresh_token=' + encodeURIComponent($env.GOOGLE_REFRESH_TOKEN) + '&grant_type=refresh_token', timeout: 15000 });
    const retryRes = await $helpers.httpRequest({ method: $('Build Request').first().json.apiMethod || 'GET', url: $('Build Request').first().json.apiEndpoint, headers: { 'Authorization': 'Bearer ' + authRes.access_token }, body: $('Build Request').first().json.apiBody, timeout: 15000 });
    return [{ json: { ...retryRes, _ctx: ctx } }];
  } catch (retryErr) {
    jarvisLog('error', 'Auth retry failed', { intent: ctx.intent, error: retryErr.message });
    return [{ json: { ...ctx, responseText: '⚠️ Authentication failed after refresh. Please re-authenticate Google OAuth.', success: false, intent: ctx.intent } }];
  }
}
jarvisLog('error', 'API request failed', { intent: ctx.intent, statusCode, statusMessage });
return [{ json: { ...ctx, responseText: '⚠️ Could not complete your request. API returned error ' + statusCode + ': ' + statusMessage + '. Please try again.', success: false, intent: ctx.intent, error: { statusCode, provider: 'contacts', intent: ctx.intent } } }];
